ownerLogin = async (_p, { input }) => {
  const o = await Owner.findOne({ email: input.email.toLowerCase() });
  if (!o) {
    throw new GraphQLError("Неверные данные", {
      extensions: { code: "UNAUTHENTICATED" },
    });
  }
